import{_ as d,o as e,c as o,ag as a}from"./chunks/framework.DTiDeF2Q.js";const p=JSON.parse('{"title":"Chmod-псевдонимы | Dotfiles (RU)","titleTemplate":":title","description":"Упростите управление правами доступа к файлам и директориям с помощью псевдонимов chmod. Быстрые ярлыки для распространённых шаблонов прав, таких как 755, 644 и других.","frontmatter":{"title":"Chmod-псевдонимы | Dotfiles","description":"Упростите управление правами доступа к файлам и директориям с помощью псевдонимов chmod. Быстрые ярлыки для распространённых шаблонов прав, таких как 755, 644 и других.","lang":"ru-RU","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Chmod-псевдонимы preview","canonical":"/ru/aliases/chmod/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Chmod-псевдонимы","pageType":"docs","schemaType":"WebPage","metaTitle":"Chmod-псевдонимы - Dotfiles (RU)","permalink":"/ru/aliases/chmod/","sidebar":true,"meta":[{"name":"keywords","content":"chmod aliases, file permissions, shell shortcuts, dotfiles, unix permissions"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Упростите управление правами доступа к файлам и директориям с помощью псевдонимов chmod."},{"name":"twitter:title","content":"Chmod-псевдонимы - Dotfiles"},{"name":"og:title","content":"Chmod-псевдонимы - Dotfiles"},{"name":"og:description","content":"Упростите управление правами доступа к файлам и директориям с помощью псевдонимов chmod."},{"name":"og:image:alt","content":"Dotfiles - Простой дизайн для вашей жизни в командной оболочке"},{"name":"og:locale","content":"ru_RU"}]},"headers":[],"relativePath":"ru/aliases/chmod/index.md","filePath":"ru/aliases/chmod/index.md","lastUpdated":1773010926000}'),r={name:"ru/aliases/chmod/index.md"};function c(h,t,i,s,l,n){return e(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="chmod-псевдонимы" tabindex="-1">Chmod-псевдонимы <a class="header-anchor" href="#chmod-псевдонимы" aria-label="Permalink to &quot;Chmod-псевдонимы&quot;">​</a></h1><p>Ярлыки для управления правами доступа к файлам и директориям.</p><p><img src="https://kura.pro/dotfiles/v2/images/titles/title-dotfiles.svg" alt="Баннер Dotfiles"></p><h2 id="обзор" tabindex="-1">Обзор <a class="header-anchor" href="#обзор" aria-label="Permalink to &quot;Обзор&quot;">​</a></h2><p>Псевдонимы chmod предоставляют упрощённый способ управления правами доступа к файлам и директориям из командной строки. Вместо запоминания числовых кодов прав используйте интуитивные псевдонимы, такие как <code>chmod_755</code> или <code>chmod_u+x</code>, для быстрой установки нужного режима доступа.</p><p>Эти псевдонимы определены в <code>chmod.aliases.sh</code> и автоматически загружаются chezmoi.</p><h2 id="справочник" tabindex="-1">Справочник <a class="header-anchor" href="#справочник" aria-label="Permalink to &quot;Справочник&quot;">​</a></h2><h3 id="распространенные-псевдонимы-прав" tabindex="-1">Распространённые псевдонимы прав <a class="header-anchor" href="#распространенные-псевдонимы-прав" aria-label="Permalink to &quot;Распространённые псевдонимы прав&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Права</th><th>Описание</th></tr></thead><tbody><tr><td><code>chmod_000</code></td><td><code>----------</code></td><td>Нет прав ни для кого</td></tr><tr><td><code>chmod_400</code></td><td><code>r--------</code></td><td>Только чтение для владельца</td></tr><tr><td><code>chmod_444</code></td><td><code>r--r--r--</code></td><td>Только чтение для всех</td></tr><tr><td><code>chmod_600</code></td><td><code>rw-------</code></td><td>Чтение/запись для владельца</td></tr><tr><td><code>chmod_644</code></td><td><code>rw-r--r--</code></td><td>Чтение/запись для владельца, только чтение для остальных</td></tr><tr><td><code>chmod_666</code></td><td><code>rw-rw-rw-</code></td><td>Чтение/запись для всех</td></tr><tr><td><code>chmod_755</code></td><td><code>rwxr-xr-x</code></td><td>Полные права владельцу, чтение/выполнение для остальных</td></tr><tr><td><code>chmod_764</code></td><td><code>rwxrw-r--</code></td><td>Полные права владельцу, чтение/запись для группы</td></tr><tr><td><code>chmod_777</code></td><td><code>rwxrwxrwx</code></td><td>Полные права для всех</td></tr></tbody></table><h3 id="псевдонимы-прав-владельца" tabindex="-1">Псевдонимы прав владельца <a class="header-anchor" href="#псевдонимы-прав-владельца" aria-label="Permalink to &quot;Псевдонимы прав владельца&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Описание</th></tr></thead><tbody><tr><td><code>chmod_u+x</code></td><td>Добавить право выполнения для владельца</td></tr><tr><td><code>chmod_u-x</code></td><td>Удалить право выполнения для владельца</td></tr><tr><td><code>chmod_u+w</code></td><td>Добавить право записи для владельца</td></tr><tr><td><code>chmod_u-w</code></td><td>Удалить право записи для владельца</td></tr><tr><td><code>chmod_u+r</code></td><td>Добавить право чтения для владельца</td></tr><tr><td><code>chmod_u-r</code></td><td>Удалить право чтения для владельца</td></tr></tbody></table><h3 id="псевдонимы-прав-группы" tabindex="-1">Псевдонимы прав группы <a class="header-anchor" href="#псевдонимы-прав-группы" aria-label="Permalink to &quot;Псевдонимы прав группы&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Описание</th></tr></thead><tbody><tr><td><code>chmod_g+x</code></td><td>Добавить право выполнения для группы</td></tr><tr><td><code>chmod_g-x</code></td><td>Удалить право выполнения для группы</td></tr><tr><td><code>chmod_g+w</code></td><td>Добавить право записи для группы</td></tr><tr><td><code>chmod_g-w</code></td><td>Удалить право записи для группы</td></tr><tr><td><code>chmod_g+r</code></td><td>Добавить право чтения для группы</td></tr><tr><td><code>chmod_g-r</code></td><td>Удалить право чтения для группы</td></tr></tbody></table><h3 id="псевдонимы-прав-остальных" tabindex="-1">Псевдонимы прав остальных <a class="header-anchor" href="#псевдонимы-прав-остальных" aria-label="Permalink to &quot;Псевдонимы прав остальных&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Описание</th></tr></thead><tbody><tr><td><code>chmod_o+x</code></td><td>Добавить право выполнения для остальных</td></tr><tr><td><code>chmod_o-x</code></td><td>Удалить право выполнения для остальных</td></tr><tr><td><code>chmod_o+w</code></td><td>Добавить право записи для остальных</td></tr><tr><td><code>chmod_o-w</code></td><td>Удалить право записи для остальных</td></tr><tr><td><code>chmod_o+r</code></td><td>Добавить право чтения для остальных</td></tr><tr><td><code>chmod_o-r</code></td><td>Удалить право чтения для остальных</td></tr></tbody></table><h3 id="псевдонимы-по-типу-фаила" tabindex="-1">Псевдонимы по типу файла <a class="header-anchor" href="#псевдонимы-по-типу-фаила" aria-label="Permalink to &quot;Псевдонимы по типу файла&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Описание</th></tr></thead><tbody><tr><td><code>chmod_755d</code></td><td>Установить права <code>rwxr-xr-x</code> для всех директорий</td></tr><tr><td><code>chmod_644f</code></td><td>Установить права <code>rw-r--r--</code> для всех файлов</td></tr></tbody></table><h3 id="рекурсивная-функция-изменения-прав" tabindex="-1">Рекурсивная функция изменения прав <a class="header-anchor" href="#рекурсивная-функция-изменения-прав" aria-label="Permalink to &quot;Рекурсивная функция изменения прав&quot;">​</a></h3><p>Функция <code>change_permission</code> применяет права рекурсивно с запросом подтверждения:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">change_permission</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 755</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/directory</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span></span></code></pre></div>',20)])])}const b=d(r,[["render",c]]);export{p as __pageData,b as default};
